sinks.expression:
$wpdb->get_var(
				// phpcs:ignore WordPress.DB.PreparedSQL.InterpolatedNotPrepared -- $table/$indexes are escaped.
				"SELECT 1 FROM `$table` WHERE meta_key IN ('$indexes') LIMIT 1"
			)

vprintf(
			'<div class="tsf-counter-wrap hide-if-no-tsf-js" %s><span class=tsf-counter title="%s">%s</span><span class=tsf-ajax></span></div>',
			[
				( $display ? '' : 'style=display:none;' ),
				\esc_attr__( 'Click to change the counter type', 'autodescription' ),
				\sprintf(
					/* translators: %s = number */
					\esc_html__( 'Characters: %s', 'autodescription' ),
					\sprintf(
						'<span id="%s">0</span>',
						\esc_attr( "{$input_id}_chars" ),
					),
				),
			],
		)

printf(
			( $block ? '<p>%s</p>' : '%s' ),
			// phpcs:ignore WordPress.Security.EscapeOutput -- Method clearly states it's not escaped.
			"<span class=description>$content</span>",
		)

printf(
			( $block ? '<p>%s</p>' : '%s' ),
			// phpcs:ignore WordPress.Security.EscapeOutput -- Method clearly states it's not escaped.
			"<span class=attention>$content</span>",
		)

printf(
			( $block ? '<p>%s</p>' : '%s' ),
			// phpcs:ignore WordPress.Security.EscapeOutput -- Method clearly states it's not escaped.
			"<span class=\"description attention\">$content</span>",
		)

vprintf(
			'<span id="tsf-social-data_%1$s" class="hidden wp-exclude-emoji" data-group="%1$s" %2$s></span>',
			[
				\esc_attr( $group ),
				// phpcs:ignore WordPress.Security.EscapeOutput -- make_data_attributes escapes.
				HTML::make_data_attributes( [ 'settings' => $settings ] ),
			],
		)

vprintf(
			implode(
				'',
				[
					'<span id="tsf-description-reference_%1$s" class="hidden wp-exclude-emoji" data-for="%1$s" ></span>',
					'<span id="tsf-description-data_%1$s" class="hidden wp-exclude-emoji" data-for="%1$s" %2$s ></span>',
				],
			),
			[
				\esc_attr( $id ),
				// phpcs:ignore WordPress.Security.EscapeOutput -- make_data_attributes escapes.
				HTML::make_data_attributes( $data ),
			],
		)

vprintf(
			'<span id="tsf-canonical-data_%1$s" class="hidden wp-exclude-emoji" data-for="%1$s" %2$s ></span>',
			[
				\esc_attr( $id ),
				// phpcs:ignore WordPress.Security.EscapeOutput -- make_data_attributes escapes.
				HTML::make_data_attributes( $data ),
			],
		)

printf(
			// '<span class=hidden id=%s data-le="%s"></span>',
			'<span class=hidden id=%s %s></span>',
			\sprintf( 'tsfLeData[%s]', (int) $post_id ),
			// phpcs:ignore WordPress.Security.EscapeOutput -- make_data_attributes escapes.
			HTML::make_data_attributes( [ 'le' => $data ] ),
		)

printf(
			// '<span class=hidden id=%s data-le-post-data="%s"></span>',
			'<span class=hidden id=%s %s></span>',
			\sprintf( 'tsfLePostData[%s]', (int) $post_id ),
			// phpcs:disable WordPress.Security.EscapeOutput -- make_data_attributes escapes.
			HTML::make_data_attributes( [
				'lePostData' => [
					'isFront'      => Query::is_static_front_page( $generator_args['id'] ),
					'primaryTerms' => $primary_terms,
				],
			] ),
			// phpcs:enable WordPress.Security.EscapeOutput
		)

printf(
			// '<span class=hidden id=%s data-le-title="%s"></span>',
			'<span class=hidden id=%s %s></span>',
			\sprintf( 'tsfLeTitleData[%s]', (int) $post_id ),
			// phpcs:disable WordPress.Security.EscapeOutput -- make_data_attributes escapes.
			HTML::make_data_attributes( [
				'leTitle' => [
					'refTitleLocked'    => $is_title_ref_locked,
					'defaultTitle'      => \esc_html( $default_title ),
					'addAdditions'      => Meta\Title\Conditions::use_branding( $generator_args ),
					'additionValue'     => \esc_html( $addition ),
					'additionPlacement' => 'left' === $seplocation ? 'before' : 'after',
				],
			] ),
			// phpcs:enable WordPress.Security.EscapeOutput
		)

printf(
			// '<span class=hidden id=%s data-le-description="%s"></span>',
			'<span class=hidden id=%s %s></span>',
			\sprintf( 'tsfLeDescriptionData[%s]', (int) $post_id ),
			// phpcs:disable WordPress.Security.EscapeOutput -- make_data_attributes escapes.
			HTML::make_data_attributes( [
				'leDescription' => [
					'refDescriptionLocked' => $is_desc_ref_locked,
					'defaultDescription'   => $default_description,
				],
			] ),
			// phpcs:enable WordPress.Security.EscapeOutput
		)

printf(
			// '<span class=hidden id=%s data-le-canonical="%s"></span>',
			'<span class=hidden id=%s %s></span>',
			\sprintf( 'tsfLeCanonicalData[%s]', (int) $post_id ),
			// phpcs:disable WordPress.Security.EscapeOutput -- make_data_attributes escapes.
			HTML::make_data_attributes( [
				'leCanonical' => [
					'refCanonicalLocked'  => $is_canonical_ref_locked,
					'defaultCanonical'    => \esc_url( $default_canonical ),
					'preferredScheme'     => Meta\URI\Utils::get_preferred_url_scheme(),
					'urlStructure'        => $permastruct,
					'parentPostSlugs'     => $parent_post_slugs ?? [],
					'parentTermSlugs'     => $parent_term_slugs_by_tax ?? [],
					'supportedTaxonomies' => $taxonomies ?? [],
					'authorSlugs'         => $author_slugs ?? [],
					'isHierarchical'      => $is_post_type_hierarchical,
					// phpcs:ignore WordPress.DateTime.RestrictedFunctions -- date() is used for URL generation. See `get_permalink()`.
					'publishDate'         => date( 'c', strtotime( \get_post( $post_id )->post_date ?? 'now' ) ),
				],
			] ),
			// phpcs:enable WordPress.Security.EscapeOutput
		)

printf(
				'<p><strong>%s</strong></p>',
				Markdown::convert(
					\sprintf(
						/* translators: %s = Redirect URL markdown */
						\esc_html__( 'There has been an error redirecting. Refresh the page or follow [this link](%s).', 'autodescription' ),
						\esc_url( $target ),
					),
					[ 'a' ],
					[ 'a_internal' => true ],
				),
			)

array_filter(
						array_unique( array_merge(
							self::get_all_forced_supported(),
							// array_keys() because get_post_types() gives a sequential array.
							array_keys( (array) \get_post_types( [ 'public' => true ] ) ),
						) ),
						'is_post_type_viewable',
					)

array_filter(
						array_unique( array_merge(
							self::get_all_forced_supported(),
							// array_values() because get_taxonomies() gives a sequential array.
							array_values( \get_taxonomies( [
								'public'   => true,
								'_builtin' => false,
							] ) ),
						) ),
						'is_taxonomy_viewable',
					)

printf(
				/* translators: %d = number of seconds */
				\esc_html__( 'Sitemap is locked for %d seconds. Try again later.', 'autodescription' ),
				(int) ( $timeout - time() ),
			)

printf(
				'<?xml-stylesheet type="text/xsl" href="%s"?>' . "\n",
				// phpcs:ignore WordPress.Security.EscapeOutput
				self::get_expected_sitemap_endpoint_url( 'xsl-stylesheet' ),
			)

printf(
							'<a href="%s" target=_blank>%s</a>',
							// phpcs:ignore WordPress.Security.EscapeOutput -- menu_page_url() escapes
							\menu_page_url( \THE_SEO_FRAMEWORK_SITE_OPTIONS_SLUG, false ) . '#autodescription-homepage-settings',
							\esc_html__( 'Edit those settings instead.', 'autodescription' ),
						)

printf(
			'<span class=hidden id=tsf-post-type-archive-data %s></span>',
			// phpcs:ignore WordPress.Security.EscapeOutput.OutputNotEscaped -- This escapes.
			HTML::make_data_attributes( [ 'postTypes' => $post_types_data ] )
		)

printf(
				'<div class="tsf-post-type-archive-wrap%s" %s>',
				// phpcs:ignore WordPress.Security.EscapeOutput.OutputNotEscaped -- Shut it, noob.
				$post_type_index ? ' hide-if-tsf-js' : '',
				// phpcs:ignore WordPress.Security.EscapeOutput.OutputNotEscaped -- This escapes.
				HTML::make_data_attributes( [ 'postType' => $post_type ] )
			)

printf(
				'<div class=tsf-tab>%s</div>',
				vsprintf(
					'<input type=radio class="tsf-nav-tab-radio tsf-input-not-saved" id=%1$s name="%2$s" %3$s><label for=%1$s class=tsf-nav-tab-label>%4$s</label>',
					[
						\esc_attr( "tsf-$id-tab-$tab" ),
						\esc_attr( "tsf-$id-tabs" ),
						1 === $tab_index ? 'checked' : '', // phpcs:ignore WordPress.Security.EscapeOutput -- plaintext.
						\sprintf(
							'%s%s',
							// phpcs:ignore WordPress.Security.EscapeOutput.OutputNotEscaped -- bug in EscapeOutputSniff
							$dashicon ? '<span class="dashicons dashicons-' . \esc_attr( $dashicon ) . ' tsf-dashicons-tabs"></span>' : '',
							// phpcs:ignore WordPress.Security.EscapeOutput.OutputNotEscaped -- bug in EscapeOutputSniff
							$name ? '<span class=tsf-nav-desktop>' . \esc_attr( $name ) . '</span>' : '',
						),
					],
				),
			)

printf(
	'<a href="%s"><h1>%s%s</h1></a>',
	\esc_url( Data\Blog::get_front_page_url(), [ 'https', 'http' ] ),
	\wp_kses(
		$logo,
		[
			'img' => [
				'src'    => true,
				'width'  => true,
				'height' => true,
			],
		],
	),
	\esc_xml(
		Sanitize::metadata_content(
			Data\Blog::get_public_blog_name() . ' &mdash; ' . \__( 'XML Sitemap', 'autodescription' ),
		),
	),
)

printf(
	'<xsl:variable name="relativeFontColor" select="\'%s\'"/>',
	'#' . Sanitize::rgb_hex(
		/**
		 * @since 2.8.0
		 * @param string $relativeFontColor A hexadecimal color.
		 */
		\apply_filters(
			'the_seo_framework_sitemap_relative_font_color',
			Format\Color::get_relative_fontcolor( $colors['main'] )
		)
	)
)

